// Issue a receipt
const receipt = await nuers.receipts.create({
  merchantId: 'MCH-2024-001',
  amount: 1250.00,
  vat: 150.00,
  discount: 0,
  items: [
    { name: 'Product A', qty: 2, unitPrice: 500.00 },
    { name: 'Product B', qty: 1, unitPrice: 250.00 },
  ],
  paymentMethod: 'cash',
  cashierId: 'EMP-001',
});

